handler_signature.ejemplo:
async handleGetPedido(req) {
  const { pedido_id } = req.params;
  if (!pedido_id) return { status: 400, error: { code: 'INVALID_INPUT', message: 'pedido_id required', details: { field: 'pedido_id' } } };
  const pedido = this.pedidosActivos.get(pedido_id);
  if (!pedido) return { status: 404, error: { code: 'RESOURCE_NOT_FOUND', message: `Pedido ${pedido_id} no encontrado`, details: { entity_type: 'pedido', entity_id: pedido_id } } };
  return { status: 200, data: { pedido } };
}
